package provisioning

import (
	"testing"

	autoscaling "k8s.io/api/autoscaling/v1beta1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"sigs.k8s.io/kueue/apis/kueue/v1beta1"
)

func TestPodSetUpdates_DoesNotSetDeprecatedAnnotations(t *testing.T) {
	wl := &v1beta1.Workload{Spec: v1beta1.WorkloadSpec{PodSets: []v1beta1.PodSet{{Name: "ps1"}}}}
	pr := &autoscaling.ProvisioningRequest{Spec: autoscaling.ProvisioningRequestSpec{ProvisioningClassName: "class1", PodSets: []autoscaling.PodSet{{PodTemplateRef: autoscaling.Reference{Name: getProvisioningRequestPodTemplateName("pr1", "ps1")}}}}}
	prc := &v1beta1.ProvisioningRequestConfig{Spec: v1beta1.ProvisioningRequestConfigSpec{PodSetUpdates: &v1beta1.PodSetUpdates{NodeSelector: []v1beta1.ProvisioningRequestNodeSelector{}}}}

	updates := podSetUpdates(nil, wl, pr, prc)
	if len(updates) != 1 {
		t.Fatalf("expected 1 podset update, got %d", len(updates))
	}
	ann := updates[0].Annotations
	if ann == nil {
		t.Fatalf("expected annotations to be set")
	}
	if ann[ConsumesAnnotationKey] != pr.Name {
		t.Fatalf("expected %s=%q, got %q", ConsumesAnnotationKey, pr.Name, ann[ConsumesAnnotationKey])
	}
	if ann[ClassNameAnnotationKey] != pr.Spec.ProvisioningClassName {
		t.Fatalf("expected %s=%q, got %q", ClassNameAnnotationKey, pr.Spec.ProvisioningClassName, ann[ClassNameAnnotationKey])
	}
	if _, ok := ann["cluster-autoscaler.kubernetes.io/consume-provisioning-request"]; ok {
		t.Fatalf("deprecated consume annotation still present")
	}
	if _, ok := ann["cluster-autoscaler.kubernetes.io/provisioning-class-name"]; ok {
		t.Fatalf("deprecated class annotation still present")
	}

	_ = metav1.TypeMeta{}
	_ = corev1.Pod{}
}

